    function data_bin_sorter($values, $mode = null, $n_bins = null, $boundaries = null, $labels = null, $format = null)
    {
        if (!is_array($values) || empty($values)) {
            return json_encode(['error' => 'Values must be a non-empty array of numbers']);
        }
        $vals = array_values($values);
        $cv = function($v) { return is_numeric($v) ? (float)$v : null; };
        $vals = array_map($cv, $vals);
        $vals = array_values(array_filter($vals, function($v) { return $v !== null; }));
